/**
 * Tests for zoom-pan module
 * 
 * Tests cover:
 * - clampZoom: boundary clamping
 * - stepZoom: in/out stepping
 * - calculateScrollZoom: wheel zoom calculation
 * - zoomTowardPoint: zoom with cursor anchoring
 * - calculateFitToScreen: fit calculation
 * - calculateFillToScreen: fill calculation
 * - resetZoomPan: reset to initial state
 * - setZoomToPreset: preset zoom with centering
 * - applyPanDelta: pan offset changes
 * - centerCanvas: centering at current zoom
 * - viewportToCanvas / canvasToViewport: coordinate conversion
 * - formatZoomPercent: string formatting
 * - getNearestPreset: nearest preset finding
 * - isZoomShortcut: keyboard shortcut detection
 */

import {
  clampZoom,
  stepZoom,
  calculateScrollZoom,
  zoomTowardPoint,
  calculateFitToScreen,
  calculateFillToScreen,
  resetZoomPan,
  setZoomToPreset,
  applyPanDelta,
  setPanPosition,
  centerCanvas,
  viewportToCanvas,
  canvasToViewport,
  formatZoomPercent,
  getNearestPreset,
  isZoomShortcut,
  MIN_ZOOM,
  MAX_ZOOM,
  ZOOM_STEP,
  ZOOM_PRESETS,
  DEFAULT_ZOOM_PAN_CONFIG,
  INITIAL_ZOOM_PAN_STATE,
} from '@lib/editor/zoom-pan';
import type { ZoomPanState, ZoomPanConfig } from '@lib/editor/zoom-pan';

// ============================================================================
// clampZoom
// ============================================================================

describe('clampZoom', () => {
  it('should return zoom within bounds', () => {
    expect(clampZoom(1.0)).toBe(1.0);
    expect(clampZoom(0.5)).toBe(0.5);
    expect(clampZoom(2.0)).toBe(2.0);
  });

  it('should clamp below minimum', () => {
    expect(clampZoom(0.01)).toBe(MIN_ZOOM);
    expect(clampZoom(-1)).toBe(MIN_ZOOM);
    expect(clampZoom(0)).toBe(MIN_ZOOM);
  });

  it('should clamp above maximum', () => {
    expect(clampZoom(5.0)).toBe(MAX_ZOOM);
    expect(clampZoom(10.0)).toBe(MAX_ZOOM);
  });

  it('should use custom config bounds', () => {
    const config: ZoomPanConfig = { ...DEFAULT_ZOOM_PAN_CONFIG, minZoom: 0.5, maxZoom: 2.0 };
    expect(clampZoom(0.3, config)).toBe(0.5);
    expect(clampZoom(3.0, config)).toBe(2.0);
    expect(clampZoom(1.0, config)).toBe(1.0);
  });
});

// ============================================================================
// stepZoom
// ============================================================================

describe('stepZoom', () => {
  it('should zoom in by step', () => {
    const result = stepZoom(1.0, 'in');
    expect(result).toBeCloseTo(1.0 + ZOOM_STEP);
  });

  it('should zoom out by step', () => {
    const result = stepZoom(1.0, 'out');
    expect(result).toBeCloseTo(1.0 - ZOOM_STEP);
  });

  it('should not exceed max zoom', () => {
    const result = stepZoom(MAX_ZOOM, 'in');
    expect(result).toBe(MAX_ZOOM);
  });

  it('should not go below min zoom', () => {
    const result = stepZoom(MIN_ZOOM, 'out');
    expect(result).toBe(MIN_ZOOM);
  });

  it('should use custom step', () => {
    const config: ZoomPanConfig = { ...DEFAULT_ZOOM_PAN_CONFIG, zoomStep: 0.25 };
    const result = stepZoom(1.0, 'in', config);
    expect(result).toBeCloseTo(1.25);
  });
});

// ============================================================================
// calculateScrollZoom
// ============================================================================

describe('calculateScrollZoom', () => {
  it('should zoom in on negative deltaY (scroll up)', () => {
    const result = calculateScrollZoom(1.0, -100);
    expect(result).toBeGreaterThan(1.0);
  });

  it('should zoom out on positive deltaY (scroll down)', () => {
    const result = calculateScrollZoom(1.0, 100);
    expect(result).toBeLessThan(1.0);
  });

  it('should not exceed max zoom', () => {
    const result = calculateScrollZoom(MAX_ZOOM, -10000);
    expect(result).toBe(MAX_ZOOM);
  });

  it('should not go below min zoom', () => {
    const result = calculateScrollZoom(MIN_ZOOM, 10000);
    expect(result).toBe(MIN_ZOOM);
  });

  it('should return same zoom for zero delta', () => {
    const result = calculateScrollZoom(1.5, 0);
    expect(result).toBeCloseTo(1.5);
  });
});

// ============================================================================
// zoomTowardPoint
// ============================================================================

describe('zoomTowardPoint', () => {
  it('should update zoom level', () => {
    const state: ZoomPanState = { zoom: 1.0, panX: 0, panY: 0 };
    const result = zoomTowardPoint(state, 2.0, { x: 400, y: 300 });
    expect(result.zoom).toBe(2.0);
  });

  it('should adjust pan to keep point anchored', () => {
    const state: ZoomPanState = { zoom: 1.0, panX: 0, panY: 0 };
    const point = { x: 400, y: 300 };
    const result = zoomTowardPoint(state, 2.0, point);

    // After zooming 2x toward (400,300), the point should remain at (400,300)
    // panX = 400 - (400 - 0) * 2 = 400 - 800 = -400
    // panY = 300 - (300 - 0) * 2 = 300 - 600 = -300
    expect(result.panX).toBe(-400);
    expect(result.panY).toBe(-300);
  });

  it('should not change pan when zooming from center with zero offset', () => {
    const state: ZoomPanState = { zoom: 1.0, panX: 0, panY: 0 };
    const result = zoomTowardPoint(state, 1.5, { x: 0, y: 0 });
    expect(result.panX).toBe(0);
    expect(result.panY).toBe(0);
  });

  it('should handle zoom out (reduce)', () => {
    const state: ZoomPanState = { zoom: 2.0, panX: -400, panY: -300 };
    const result = zoomTowardPoint(state, 1.0, { x: 400, y: 300 });
    expect(result.zoom).toBe(1.0);
    // Pan should adjust back toward origin
    expect(result.panX).toBeCloseTo(0);
    expect(result.panY).toBeCloseTo(0);
  });
});

// ============================================================================
// calculateFitToScreen
// ============================================================================

describe('calculateFitToScreen', () => {
  it('should fit 1920x1080 into 960x540 viewport', () => {
    const result = calculateFitToScreen(
      { width: 1920, height: 1080 },
      { width: 960, height: 540 },
      0 // no padding
    );
    expect(result.zoom).toBeCloseTo(0.5);
  });

  it('should respect padding', () => {
    const result = calculateFitToScreen(
      { width: 1920, height: 1080 },
      { width: 1960, height: 1120 },
      20
    );
    // Available: 1920x1080 → zoom = 1.0
    expect(result.zoom).toBeCloseTo(1.0);
  });

  it('should center canvas in viewport', () => {
    const result = calculateFitToScreen(
      { width: 1920, height: 1080 },
      { width: 960, height: 540 },
      0
    );
    // Canvas at 0.5x: 960x540, viewport: 960x540 → centered at 0,0
    expect(result.panX).toBeCloseTo(0);
    expect(result.panY).toBeCloseTo(0);
  });

  it('should handle wider viewport', () => {
    const result = calculateFitToScreen(
      { width: 1920, height: 1080 },
      { width: 2000, height: 500 },
      0
    );
    // Height-limited: 500/1080 ≈ 0.463
    expect(result.zoom).toBeCloseTo(500 / 1080, 2);
    // Centered horizontally
    const scaledWidth = 1920 * result.zoom;
    expect(result.panX).toBeCloseTo((2000 - scaledWidth) / 2, 0);
  });

  it('should return initial state for zero/negative viewport', () => {
    const result = calculateFitToScreen(
      { width: 1920, height: 1080 },
      { width: 0, height: 0 }
    );
    expect(result).toEqual(INITIAL_ZOOM_PAN_STATE);
  });
});

// ============================================================================
// calculateFillToScreen
// ============================================================================

describe('calculateFillToScreen', () => {
  it('should fill viewport (may crop)', () => {
    const result = calculateFillToScreen(
      { width: 1920, height: 1080 },
      { width: 960, height: 540 }
    );
    // Both scales are 0.5, so fill is also 0.5
    expect(result.zoom).toBeCloseTo(0.5);
  });

  it('should use larger scale factor', () => {
    const result = calculateFillToScreen(
      { width: 1920, height: 1080 },
      { width: 1000, height: 800 }
    );
    // scaleX = 1000/1920 ≈ 0.521, scaleY = 800/1080 ≈ 0.741
    // fill uses max → 0.741
    expect(result.zoom).toBeCloseTo(800 / 1080, 2);
  });
});

// ============================================================================
// resetZoomPan
// ============================================================================

describe('resetZoomPan', () => {
  it('should return initial state', () => {
    const result = resetZoomPan();
    expect(result).toEqual(INITIAL_ZOOM_PAN_STATE);
    expect(result.zoom).toBe(1.0);
    expect(result.panX).toBe(0);
    expect(result.panY).toBe(0);
  });

  it('should return a new object each time', () => {
    const a = resetZoomPan();
    const b = resetZoomPan();
    expect(a).not.toBe(b);
    expect(a).toEqual(b);
  });
});

// ============================================================================
// setZoomToPreset
// ============================================================================

describe('setZoomToPreset', () => {
  it('should set zoom and center canvas', () => {
    const result = setZoomToPreset(
      2.0,
      { width: 1920, height: 1080 },
      { width: 1920, height: 1080 }
    );
    expect(result.zoom).toBe(2.0);
    // At 2x, canvas is 3840x2160, viewport 1920x1080
    // panX = (1920 - 3840) / 2 = -960
    expect(result.panX).toBeCloseTo(-960);
    expect(result.panY).toBeCloseTo(-540);
  });

  it('should clamp to valid range', () => {
    const result = setZoomToPreset(
      10.0,
      { width: 1920, height: 1080 },
      { width: 1920, height: 1080 }
    );
    expect(result.zoom).toBe(MAX_ZOOM);
  });
});

// ============================================================================
// applyPanDelta / setPanPosition
// ============================================================================

describe('applyPanDelta', () => {
  it('should add delta to current pan', () => {
    const state: ZoomPanState = { zoom: 1.0, panX: 100, panY: 50 };
    const result = applyPanDelta(state, 20, 30);
    expect(result.panX).toBe(120);
    expect(result.panY).toBe(80);
    expect(result.zoom).toBe(1.0); // zoom unchanged
  });

  it('should handle negative deltas', () => {
    const state: ZoomPanState = { zoom: 1.5, panX: 0, panY: 0 };
    const result = applyPanDelta(state, -50, -30);
    expect(result.panX).toBe(-50);
    expect(result.panY).toBe(-30);
  });
});

describe('setPanPosition', () => {
  it('should set absolute pan position', () => {
    const state: ZoomPanState = { zoom: 2.0, panX: 100, panY: 50 };
    const result = setPanPosition(state, 200, 300);
    expect(result.panX).toBe(200);
    expect(result.panY).toBe(300);
    expect(result.zoom).toBe(2.0);
  });
});

// ============================================================================
// centerCanvas
// ============================================================================

describe('centerCanvas', () => {
  it('should center canvas at current zoom', () => {
    const state: ZoomPanState = { zoom: 1.0, panX: -500, panY: -300 };
    const result = centerCanvas(
      state,
      { width: 1920, height: 1080 },
      { width: 1920, height: 1080 }
    );
    expect(result.panX).toBeCloseTo(0);
    expect(result.panY).toBeCloseTo(0);
    expect(result.zoom).toBe(1.0);
  });

  it('should center at 50% zoom', () => {
    const state: ZoomPanState = { zoom: 0.5, panX: 0, panY: 0 };
    const result = centerCanvas(
      state,
      { width: 1920, height: 1080 },
      { width: 1920, height: 1080 }
    );
    // At 0.5x: scaled canvas = 960x540, viewport = 1920x1080
    // panX = (1920 - 960) / 2 = 480
    expect(result.panX).toBeCloseTo(480);
    expect(result.panY).toBeCloseTo(270);
  });
});

// ============================================================================
// Coordinate conversion
// ============================================================================

describe('viewportToCanvas', () => {
  it('should convert at zoom 1.0 with no pan', () => {
    const result = viewportToCanvas({ x: 100, y: 200 }, { zoom: 1.0, panX: 0, panY: 0 });
    expect(result.x).toBe(100);
    expect(result.y).toBe(200);
  });

  it('should account for zoom', () => {
    const result = viewportToCanvas({ x: 200, y: 200 }, { zoom: 2.0, panX: 0, panY: 0 });
    expect(result.x).toBe(100);
    expect(result.y).toBe(100);
  });

  it('should account for pan', () => {
    const result = viewportToCanvas({ x: 150, y: 100 }, { zoom: 1.0, panX: 50, panY: 100 });
    expect(result.x).toBe(100);
    expect(result.y).toBe(0);
  });

  it('should account for both zoom and pan', () => {
    const result = viewportToCanvas({ x: 300, y: 400 }, { zoom: 2.0, panX: 100, panY: 200 });
    // x = (300 - 100) / 2 = 100
    // y = (400 - 200) / 2 = 100
    expect(result.x).toBe(100);
    expect(result.y).toBe(100);
  });
});

describe('canvasToViewport', () => {
  it('should convert at zoom 1.0 with no pan', () => {
    const result = canvasToViewport({ x: 100, y: 200 }, { zoom: 1.0, panX: 0, panY: 0 });
    expect(result.x).toBe(100);
    expect(result.y).toBe(200);
  });

  it('should be inverse of viewportToCanvas', () => {
    const state: ZoomPanState = { zoom: 1.5, panX: 30, panY: -20 };
    const original = { x: 100, y: 200 };
    const viewport = canvasToViewport(original, state);
    const back = viewportToCanvas(viewport, state);
    expect(back.x).toBeCloseTo(original.x);
    expect(back.y).toBeCloseTo(original.y);
  });
});

